 1→import { NavigatorScreenParams, CompositeScreenProps } from '@react-navigation/native';
 2→import { NativeStackScreenProps } from '@react-navigation/native-stack';
 3→import { BottomTabScreenProps } from '@react-navigation/bottom-tabs';
 4→
 5→export type MainTabParamList = {
 6→  Home: undefined;
 7→  Vault: undefined;
 8→  Cart: undefined;
 9→  Menu: undefined;
10→};
11→
12→export type RootStackParamList = {
13→  MainTabs: NavigatorScreenParams<MainTabParamList>;
14→  CartDetail: { cartId: string };
15→  Paywall: undefined;
16→  History: undefined;
17→};
18→
19→export type RootStackScreenProps<T extends keyof RootStackParamList> =
20→  NativeStackScreenProps<RootStackParamList, T>;
21→
22→export type MainTabScreenProps<T extends keyof MainTabParamList> =
23→  CompositeScreenProps<
24→    BottomTabScreenProps<MainTabParamList, T>,
25→    NativeStackScreenProps<RootStackParamList>
26→  >;
27→
28→declare global {
29→  namespace ReactNavigation {
30→    interface RootParamList extends RootStackParamList {}
31→  }
32→}
