 1→import { NavigationContainer, DefaultTheme } from '@react-navigation/native';
 2→import { createNativeStackNavigator } from '@react-navigation/native-stack';
 3→import React from 'react';
 4→
 5→import { CartDetailScreen } from '../screens/cart/CartDetailScreen';
 6→import { HistoryScreen } from '../screens/history/HistoryScreen';
 7→import { LoadingScreen } from '../screens/LoadingScreen';
 8→import { OnboardingFlow } from '../screens/onboarding/OnboardingFlow';
 9→import { PaywallScreen } from '../screens/paywall/PaywallScreen';
10→import { useAppStore } from '../state/useAppStore';
11→import { colors } from '../theme/colors';
12→import { MainTabNavigator } from './MainTabNavigator';
13→import { RootStackParamList } from './types';
14→
15→const Stack = createNativeStackNavigator<RootStackParamList>();
16→
17→const navigationTheme = {
18→  ...DefaultTheme,
19→  colors: {
20→    ...DefaultTheme.colors,
21→    background: colors.canvas,
22→    card: colors.surface,
23→    text: colors.ink,
24→    border: colors.line,
25→    primary: colors.brand,
26→  },
27→};
28→
29→export function RootNavigator() {
30→  const isBootstrapping = useAppStore(state => state.isBootstrapping);
31→  const appState = useAppStore(state => state.appState);
32→  const errorMessage = useAppStore(state => state.errorMessage);
33→
34→  if (isBootstrapping) {
35→    return <LoadingScreen message="Bootstrapping the Grock React Native workspace..." />;
36→  }
37→
38→  if (errorMessage) {
39→    return <LoadingScreen message={errorMessage} />;
40→  }
41→
42→  if (!appState) {
43→    return <LoadingScreen message="No app state loaded." />;
44→  }
45→
46→  if (!appState.preferences.hasCompletedOnboarding) {
47→    return <OnboardingFlow />;
48→  }
49→
50→  return (
51→    <NavigationContainer theme={navigationTheme}>
52→      <Stack.Navigator
53→        initialRouteName="MainTabs"
54→        screenOptions={{
55→          headerShadowVisible: false,
56→          headerStyle: { backgroundColor: colors.canvas },
57→          headerTintColor: colors.ink,
58→          headerTitleStyle: { fontWeight: '700' },
59→          contentStyle: { backgroundColor: colors.canvas },
60→        }}
61→      >
62→        <Stack.Screen
63→          name="MainTabs"
64→          component={MainTabNavigator}
65→          options={{ headerShown: false }}
66→        />
67→        <Stack.Screen
68→          name="CartDetail"
69→          component={CartDetailScreen}
70→          options={{ title: 'Cart', presentation: 'card' }}
71→        />
72→        <Stack.Screen
73→          name="Paywall"
74→          component={PaywallScreen}
75→          options={{ title: 'Grock Pro', presentation: 'modal' }}
76→        />
77→        <Stack.Screen
78→          name="History"
79→          component={HistoryScreen}
80→          options={{ title: 'History', presentation: 'card' }}
81→        />
82→      </Stack.Navigator>
83→    </NavigationContainer>
84→  );
85→}
