 22→export function HomeScreen({ navigation }: Props) {
 23→  const appState = useAppStore(state => state.appState);
 24→  const [tab, setTab] = useState<HomeTab>('active');
 25→
 26→  const summary = useMemo(
 27→    () => (appState ? computeDashboardSummary(appState) : null),
 28→    [appState]
 29→  );
 30→
 31→  const listData = useMemo(() => {
 32→    if (!summary) return [];
 33→    if (tab === 'active') return summary.activeCarts;
 34→    if (tab === 'completed') return summary.completedCarts;
 35→    return [];
 36→  }, [summary, tab]);
 37→
 38→  const renderItem = useCallback(
 39→    ({ item, index }: { item: Cart; index: number }) => {
 40→      if (!appState) return null;
 41→      const total = computeCartTotal(appState.vault, item);
 42→
 43→      if (tab === 'completed') {
 44→        return (
 45→          <Animated.View entering={FadeInUp.delay(index * 60)}>
 46→            <CompletedCartCard
 47→              cart={item}
 48→              total={total}
 49→              onPress={() => navigation.navigate('CartDetail', { cartId: item.id })}
 50→            />
 51→          </Animated.View>
 52→        );
 53→      }
 54→
 55→      return (
 56→        <Animated.View entering={FadeInUp.delay(index * 60)}>
 57→          <ActiveCartCard
 58→            cart={item}
 59→            total={total}
 60→            onPress={() => navigation.navigate('CartDetail', { cartId: item.id })}
 61→          />
 62→        </Animated.View>
 63→      );
 64→    },
 65→    [appState, tab, navigation]
 66→  );
 67→
 68→  if (!appState || !summary) return null;
 69→
 70→  const ListHeader = (
 71→    <View style={styles.header}>
 72→      <HomeHeader
 73→        userName={appState.user.name}
 74→        activeCarts={summary.activeCarts.length}
 75→        itemCount={summary.itemCount}
 76→      />
 77→      <QuickActions
 78→        onBrowseVault={() => navigation.navigate('Vault')}
 79→        onHistory={() => navigation.navigate('History')}
 80→        onPaywall={() => navigation.navigate('Paywall')}
 81→      />
 82→      <View style={styles.statRow}>
 83→        <StatCard label="Active carts" value={String(summary.activeCarts.length)} />
 84→        <StatCard label="Vault items" value={String(summary.itemCount)} />
 85→        <StatCard label="Total spent" value={formatCurrency(summary.totalSpent)} />
 86→      </View>
 87→      <HomeTabBar activeTab={tab} onTabChange={setTab} />
 88→    </View>
 89→  );
 90→
 91→  return (
 92→    <FlatList
 93→      data={tab === 'insights' ? [] : listData}
 94→      keyExtractor={item => item.id}
 95→      renderItem={renderItem}
 96→      style={styles.screen}
 97→      contentContainerStyle={styles.content}
 98→      ListHeaderComponent={ListHeader}
 99→      ListFooterComponent={
100→        tab === 'insights' && summary ? <InsightsPanel summary={summary} /> : null
101→      }
102→      ListEmptyComponent={
103→        tab !== 'insights' ? <HomeEmptyState /> : null
104→      }
105→      initialNumToRender={6}
106→      maxToRenderPerBatch={5}
107→      windowSize={5}
108→    />
109→  );
110→}
111→
112→const styles = StyleSheet.create({
113→  screen: {
114→    flex: 1,
115→    backgroundColor: colors.canvas,
116→  },
117→  content: {
118→    padding: spacing.xl,
119→    gap: spacing.lg,
120→  },
121→  header: {
122→    gap: 18,
123→  },
124→  statRow: {
125→    flexDirection: 'row',
126→    gap: 10,
127→  },
128→});
