  1→import React, { useMemo, useState } from 'react';
  2→import {
  3→  FlatList,
  4→  StyleSheet,
  5→  Text,
  6→  TextInput,
  7→  View,
  8→} from 'react-native';
  9→import Animated, { FadeInUp } from 'react-native-reanimated';
 10→
 11→import { AnimatedPressable } from '../../components/AnimatedPressable';
 12→import { Card } from '../../components/Card';
 13→import { EmptyState } from '../../components/EmptyState';
 14→import { Cart, computeCartTotal } from '../../domain/models';
 15→import { formatCurrency } from '../../lib/format';
 16→import { MainTabScreenProps } from '../../navigation/types';
 17→import { useAppStore } from '../../state/useAppStore';
 18→import { colors } from '../../theme/colors';
 19→import { spacing } from '../../theme/spacing';
 20→import { typography } from '../../theme/typography';
 21→import { ProgressBar } from '../../components/ProgressBar';
 22→
 23→type Props = MainTabScreenProps<'Cart'>;
 24→
 25→const CartCard = React.memo(function CartCard({
 26→  cart,
 27→  total,
 28→  onPress,
 29→}: {
 30→  cart: Cart;
 31→  total: number;
 32→  onPress: () => void;
 33→}) {
 34→  const fulfilledCount = cart.cartItems.filter(i => i.isFulfilled).length;
 35→  const progress = cart.cartItems.length > 0 ? fulfilledCount / cart.cartItems.length : 0;
 36→
 37→  return (
 38→    <AnimatedPressable
 39→      onPress={onPress}
 40→      accessibilityLabel={`${cart.name}, ${cart.cartItems.length} items, ${formatCurrency(total)}`}
 41→      accessibilityRole="button"
 42→    >
 43→      <Animated.View entering={FadeInUp.duration(300)} style={styles.cartCard}>
 44→        <View style={styles.cartCardHeader}>
 45→          <Text style={styles.cartName}>{cart.name}</Text>
 46→          <View style={[styles.statusBadge, cart.status === 'shopping' && styles.statusShopping]}>
 47→            <Text style={styles.statusText}>{cart.status}</Text>
 48→          </View>
 49→        </View>
 50→        <ProgressBar
 51→          progress={progress}
 52→          color={colors.success}
 53→          accessibilityLabel={`${fulfilledCount} of ${cart.cartItems.length} items done`}
 54→        />
 55→        <View style={styles.cartCardFooter}>
 56→          <Text style={styles.cartMeta}>
 57→            {cart.cartItems.length} item{cart.cartItems.length === 1 ? '' : 's'}
 58→          </Text>
 59→          <Text style={styles.cartTotal}>{formatCurrency(total)}</Text>
 60→        </View>
 61→      </Animated.View>
 62→    </AnimatedPressable>
 63→  );
 64→});
 65→
 66→export function CartListScreen({ navigation }: Props) {
 67→  const appState = useAppStore(state => state.appState);
 68→  const draftSelections = useAppStore(state => state.draftSelections);
 69→  const createCart = useAppStore(state => state.createCart);
 70→  const [cartName, setCartName] = useState('');
 71→  const [budget, setBudget] = useState('120');
 72→
 73→  const activeCarts = useMemo(
 74→    () => appState?.vault.carts.filter(c => !c.isDeleted && c.status !== 'completed') ?? [],
 75→    [appState]
 76→  );
 77→
 78→  if (!appState) return null;
 79→
 80→  const selectedItems = Object.entries(draftSelections).map(([itemId, quantity]) => ({
 81→    itemId,
 82→    quantity,
 83→  }));
 84→
 85→  const handleCreateCart = async () => {
 86→    if (!selectedItems.length) return;
 87→    const parsedBudget = Number(budget);
 88→    if (!cartName.trim() || !Number.isFinite(parsedBudget)) return;
 89→    await createCart({ name: cartName, budget: parsedBudget, selectedItems });
 90→    setCartName('');
 91→  };
 92→
 93→  const renderItem = ({ item }: { item: Cart }) => (
 94→    <CartCard
 95→      cart={item}
 96→      total={computeCartTotal(appState.vault, item)}
 97→      onPress={() => navigation.navigate('CartDetail', { cartId: item.id })}
 98→    />
 99→  );
100→
101→  return (
102→    <FlatList
103→      data={activeCarts}
104→      keyExtractor={item => item.id}
105→      renderItem={renderItem}
106→      style={styles.screen}
107→      contentContainerStyle={styles.content}
108→      ListHeaderComponent={
109→        <Card style={styles.createCard}>
110→          <Text style={styles.createTitle}>Quick create</Text>
111→          <Text style={styles.createHint}>
112→            Select items in Vault tab, then create a cart here.
113→          </Text>
114→          <TextInput
115→            style={styles.input}
116→            value={cartName}
117→            onChangeText={setCartName}
118→            placeholder="Cart name"
119→            placeholderTextColor={colors.mutedInk}
120→            accessibilityLabel="Cart name"
121→          />
122→          <TextInput
123→            style={styles.input}
124→            value={budget}
125→            onChangeText={setBudget}
126→            placeholder="Budget"
127→            placeholderTextColor={colors.mutedInk}
128→            keyboardType="decimal-pad"
129→            accessibilityLabel="Budget amount"
130→          />
131→          <AnimatedPressable
132→            style={[styles.createButton, !selectedItems.length && styles.buttonDisabled]}
133→            onPress={() => { handleCreateCart().catch(() => undefined); }}
134→            disabled={!selectedItems.length}
135→            accessibilityRole="button"
136→            accessibilityLabel={`Create cart from ${selectedItems.length} selected items`}
137→            accessibilityState={{ disabled: !selectedItems.length }}
