15→export function BudgetBar({ spent, budget }: BudgetBarProps) {
16→  const ratio = budget > 0 ? spent / budget : 0;
17→  const clamped = Math.min(ratio, 1.2);
18→  const displayPercent = Math.min(clamped, 1);
19→
20→  const barColor =
21→    ratio > 1.0 ? colors.danger :
22→    ratio > 0.9 ? colors.brand :
23→    ratio > 0.7 ? colors.warning :
24→    colors.success;
25→
26→  const fillStyle = useAnimatedStyle(() => ({
27→    width: `${withSpring(displayPercent * 100, motion.gentle)}%` as any,
28→    backgroundColor: barColor,
29→  }));
30→
31→  return (
32→    <View
33→      style={styles.container}
34→      accessibilityLabel={`Budget: ${formatCurrency(spent)} of ${formatCurrency(budget)}`}
35→    >
36→      <View style={styles.labelRow}>
37→        <Text style={styles.spent}>{formatCurrency(spent)}</Text>
38→        <Text style={styles.budget}>/ {formatCurrency(budget)}</Text>
39→      </View>
40→      <View style={styles.track}>
41→        <Animated.View style={[styles.fill, fillStyle]} />
42→      </View>
43→      {ratio > 1 && (
44→        <Text style={styles.over}>
45→          {formatCurrency(spent - budget)} over budget
46→        </Text>
47→      )}
48→    </View>
