16→  disabled?: boolean;
17→  style?: StyleProp<ViewStyle>;
18→  children: React.ReactNode;
19→  hitSlop?: PressableProps['hitSlop'];
20→}
21→
22→export function AnimatedPressable({
23→  onPress,
24→  onLongPress,
25→  disabled,
26→  style,
27→  children,
28→  hitSlop,
29→  ...a11yProps
30→}: AnimatedPressableProps) {
31→  const pressed = useSharedValue(0);
32→
33→  const animatedStyle = useAnimatedStyle(() => ({
34→    transform: [{ scale: withSpring(pressed.value ? 0.97 : 1, motion.snappy) }],
35→    opacity: withSpring(pressed.value ? 0.85 : 1, motion.snappy),
36→  }));
37→
38→  return (
39→    <ReanimatedPressable
40→      onPress={disabled ? undefined : onPress}
41→      onLongPress={disabled ? undefined : onLongPress}
42→      onPressIn={() => { pressed.value = 1; }}
43→      onPressOut={() => { pressed.value = 0; }}
44→      style={[animatedStyle, style]}
45→      hitSlop={hitSlop}
46→      disabled={disabled}
47→      {...a11yProps}
48→    >
49→      {children}
50→    </ReanimatedPressable>
51→  );
52→}
